// ── GANTI 4 NILAI INI, TIDAK PERLU UBAH LAGI ────────────
flow.set('app_url',            'https://GANTI-URL-GETFUEL.app');
flow.set('nodered_secret',     'GANTI-NODERED_WEBHOOK_SECRET');
flow.set('cron_secret',        'GANTI-CRON_SECRET');
flow.set('fonnte_webhook_key', 'GANTI-FONNTE_WEBHOOK_KEY');
// ─────────────────────────────────────────────────────────

node.status({ fill: 'green', shape: 'dot', text: 'Config OK ✓' });
return null;

msg.method  = 'POST';
msg.headers = {
  'Content-Type': 'application/json',
  'x-webhook-secret': flow.get('nodered_secret')
};
msg.url     = flow.get('app_url') + '/api/webhooks/nodered';
msg.payload = JSON.stringify({ action: 'get_pending_recipients', limit: 20 });
return msg;

const data = msg.payload;
if (!data || !data.ok || !Array.isArray(data.recipients) || data.recipients.length === 0) {
  node.status({ fill: 'grey', shape: 'ring', text: 'kosong' });
  return null;
}
node.status({ fill: 'blue', shape: 'dot', text: data.recipients.length + ' pending' });
return [data.recipients.map(r => ({ payload: r }))];

const r = msg.payload;
if (!r || !r.phone || !r.id || !r.fonnte_token) return null;

msg._recipient_id = r.id;

let phone = String(r.phone).replace(/\D/g, '');
if (phone.startsWith('0')) phone = '62' + phone.slice(1);

const content = (r.broadcast && r.broadcast.content) ? r.broadcast.content : '(pesan kosong)';

msg.method  = 'POST';
msg.headers = { 'Authorization': r.fonnte_token, 'Content-Type': 'application/json' };
msg.url     = 'https://api.fonnte.com/send';
msg.payload = JSON.stringify({ target: phone, message: content, countryCode: '62' });
return msg;

const ok = msg.payload && msg.payload.status === true;
node.status({ fill: ok ? 'green' : 'red', shape: 'dot', text: ok ? 'sent' : 'failed' });
msg.method  = 'POST';
msg.headers = { 'Content-Type': 'application/json', 'x-webhook-secret': flow.get('nodered_secret') };
msg.url     = flow.get('app_url') + '/api/webhooks/nodered';
msg.payload = JSON.stringify({ action: 'mark_recipient', recipient_id: msg._recipient_id, status: ok ? 'sent' : 'failed' });
return msg;

msg.method  = 'POST';
msg.headers = { 'Authorization': 'Bearer ' + flow.get('cron_secret'), 'Content-Type': 'application/json' };
msg.url     = flow.get('app_url') + '/api/wa/process-queue';
msg.payload = '{}';
return msg;

const r = msg.payload;
if (!r || !r.ok) { node.status({ fill: 'red', shape: 'dot', text: 'error' }); return msg; }
const s = 'sent=' + (r.sent||0) + ' fail=' + (r.failed||0) + ' q=' + (r.processed||0);
node.status({ fill: (r.sent||0) > 0 ? 'green' : 'grey', shape: 'dot', text: s });
return msg;

msg.method  = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.url     = flow.get('app_url') + '/api/wa/incoming?key=' + encodeURIComponent(flow.get('fonnte_webhook_key'));
msg.payload = JSON.stringify(msg.payload);
return msg;

msg.payload    = JSON.stringify({ ok: true });
msg.statusCode = 200;
msg.headers    = { 'Content-Type': 'application/json' };
return msg;
